<!DOCTYPE html>
<html>
<head>
<title>Mini Spreadsheet</title>
<style>
table {
  border-collapse: collapse;
}

td {
  width: 50px;
  height: 30px;
  text-align: center;
  font-size: 16px;
  border: 1px solid black;
}

input[type="text"] {
  width: 46px;
  height: 26px;
  box-sizing: border-box;
}

button {
  padding: 5px 10px;
  margin: 5px;
  cursor: pointer;
}
</style>
</head>
<body>

<table>
  <thread>
    <tr>
      <th>A</th>
      <th>B</th>
      <th>C</th>
      <th>D</th>
      <th>E</th>
      <th>F</th>
      <th>G</th>
      <th>H</th>
      <th>I</th>
      <th>J</th>
    </tr>
  </thread>
  <tbody>
    <tr>
      <td><input type="text" id="cell-A1" value="1"></td>
      <td><input type="text" id="cell-B1" value="2"></td>
      <td><input type="text" id="cell-C1" value="3"></td>
      <td><input type="text" id="cell-D1" value="4"></td>
      <td><input type="text" id="cell-E1" value="5"></td>
      <td><input type="text" id="cell-F1" value="6"></td>
      <td><input type="text" id="cell-G1" value="7"></td>
      <td><input type="text" id="cell-H1" value="8"></td>
      <td><input type="text" id="cell-I1" value="9"></td>
      <td><input type="text" id="cell-J1" value="10"></td>
    </tr>
    <tr>
      <td><input type="text" id="cell-A2" value="=A1+B1"></td>
      <td><input type="text" id="cell-B2" value="=A2*C1"></td>
      <td><input type="text" id="cell-C2" value="=D1-E1"></td>
      <td><input type="text" id="cell-D2" value="=F1/G1"></td>
      <td><input type="text" id="cell-E2" value="=H1+I1"></td>
      <td><input type="text" id="cell-F2" value="=J1*A1"></td>
      <td><input type="text" id="cell-G2" value="=(A1*B1)+C1"></td>
      <td><input type="text" id="cell-H2" value="=D2+E2"></td>
      <td><input type="text" id="cell-I2" value="=F2/G2"></td>
      <td><input type="text" id="cell-J2" value="=(A1+B1)*C1"></td>
    </tr>
    <tr>
      <td><input type="text" id="cell-A3" value="11"></td>
      <td><input type="text" id="cell-B3" value="12"></td>
      <td><input type="text" id="cell-C3" value="13"></td>
      <td><input type="text" id="cell-D3" value="14"></td>
      <td><input type="text" id="cell-E3" value="15"></td>
      <td><input type="text" id="cell-F3" value="16"></td>
      <td><input type="text" id="cell-G3" value="17"></td>
      <td><input type="text" id="cell-H3" value="18"></td>
      <td><input type="text" id="cell-I3" value="19"></td>
      <td><input type="text" id="cell-J3" value="20"></td>
    </tr>
    <tr>
      <td><input type="text" id="cell-A4" value="=A3+B3"></td>
      <td><input type="text" id="cell-B4" value="=C3*D3"></td>
      <td><input type="text" id="cell-C4" value="=E3-F3"></td>
      <td><input type="text" id="cell-D4" value="=G3/H3"></td>
      <td><input type="text" id="cell-E4" value="=I3+J3"></td>
      <td><input type="text" id="cell-F4" value="=A4*B4"></td>
      <td><input type="text" id="cell-G4" value="=(A3*B3)+C3"></td>
      <td><input type="text" id="cell-H4" value="=D4+E4"></td>
      <td><input type="text" id="cell-I4" value="=F4/G4"></td>
      <td><input type="text" id="cell-J4" value="=(A3+B3)*C3"></td>
    </tr>
  </tbody>
</table>

<button id="export">Export CSV</button>
<textarea id="csv" rows="10" cols="80"></textarea>

<script>
const sheet = {
  set: function(cellId, formula) {
    document.getElementById(cellId).value = formula;
    evaluate();
  },
  get: function(cellId) {
    return document.getElementById(cellId).value;
  },
  raw: function(cellId) {
    return document.getElementById(cellId).innerText;
  }
};

function evaluate() {
  for (let i = 1; i <= 10; i++) {
    for (let j = 1; j <= 10; j++) {
      const cellId = `cell-${i}-${j}`;
      let value = document.getElementById(cellId).value;

      if (value.startsWith("=")) {
        try {
          // Evaluate the formula
          value = eval(value);
        } catch (e) {
          value = "#ERR";
        }
      } else if (value === "") {
        value = 0;
      }

      document.getElementById(cellId).value = value;
    }
  }
}

document.getElementById("export").addEventListener("click", () => {
  const csvData = [];
  for (let i = 1; i <= 10; i++) {
    let row = "";
    for (let j = 1; j <= 10; j++) {
      const cellId = `cell-${i}-${j}`;
      row += document.getElementById(cellId).value + ",";
    }
    csvData.push(row);
  }

  document.getElementById("csv").value = csvData.join("\n");
});

// Initial evaluation
evaluate();
</script>

</body>
</html>
